public class CharExtractionDemo {
 public static void main(String[] args) {
 String str = "Java";

 // Using charAt() to extract each character
 for (int i = 0; i < str.length(); i++) {
 char ch = str.charAt(i);
 System.out.println("Index " + i + ": " + ch);
 }

 // Safe extraction with bounds checking
 int index = 2;
 if (index >= 0 && index < str.length()) {
 System.out.println("Character at " + index + ": " + str.charAt(index));
 } else {
 System.out.println("Invalid index!");
 }

 // Character arithmetic
 char upper = 'A';
 char lower = (char)(upper + 32); // Convert to lowercase
 System.out.println("Lowercase: " + lower);
 }
}

public class SubstringDemo {
 public static void main(String[] args) {
 String original = "Programming";

 // Using substring() - two overloaded versions
 String sub1 = original.substring(3); // From index 3 to end
 String sub2 = original.substring(3, 7); // From index 3 to 6

 System.out.println("Original: " + original);
 System.out.println("substring(3): " + sub1); // "gramming"
 System.out.println("substring(3,7): " + sub2); // "gram"

 // Using toCharArray()
 char[] chars = original.toCharArray();
 System.out.println("Character array: ");
 for (char c : chars) {
 System.out.print(c + " ");
 }

 // Using getChars() - copy portion to array
 char[] dest = new char[5];
 original.getChars(3, 8, dest, 0); // Copy indices 3-7 to dest
 System.out.println("\nCopied via getChars: " + new String(dest));
 }
}

import java.util.*;

public class CharacterFrequency {
 public static void main(String[] args) {
 String str = "Java Programming";
 Map<Character, Integer> freq = new LinkedHashMap<>();

 // Extract each character using charAt() and count
 for (int i = 0; i < str.length(); i++) {
 char ch = str.charAt(i);
 freq.put(ch, freq.getOrDefault(ch, 0) + 1);
 }

 // Display frequencies
 System.out.println("Character frequencies:");
 for (Map.Entry<Character, Integer> entry : freq.entrySet()) {
 System.out.println("'" + entry.getKey() + "": " + entry.getValue());
 }

 // Using streams (Java 8+)
 System.out.println("\nUsing Streams:");
 str.chars()
 .mapToObj(c -> (char) c)
 .forEach(c -> System.out.print(c + " "));
 }
}
